def is_samepatterns(patterns, seq):
    if len(patterns) != len(seq):
        return False

    # Create a mapping from pattern to sequence element
    pattern_to_seq = {}
    pattern_count = 0

    for pattern, element in zip(patterns, seq):
        if pattern in pattern_to_seq:
            # If pattern exists, its mapped sequence element must match
            if pattern_to_seq[pattern] != element:
                return False
        else:
            # New pattern, assign the next available sequence element
            pattern_to_seq[pattern] = element
            pattern_count += 1

    # All patterns must be used (otherwise, some sequence elements would be unused)
    return pattern_count == len(patterns)
