    Returns the number of divisors of a given integer n.
    """
    if n <= 0:
        return 0

    count = 0
    # Check divisors up to the square root of n
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            # If i is a divisor, n/i is also a divisor
            if i * i == n:
                count += 1  # Perfect square, count only once
            else:
                count += 2  # Count both i and n/i
    return count
