def next_smallest_palindrome(n):
    if n < 0:
        return -1
    if n == 0:
        return 0
    if n < 10:
        return n + 1 if n != 9 else 11

    s = str(n)
    length = len(s)
    half_len = length // 2
    left_half = s[:half_len]
    right_half = s[half_len:]

    if s == s[::-1]:
        # Find the next palindrome greater than n
        # Increment the left half and mirror it
        left_half_num = int(left_half)
        left_half_num += 1
        new_left_half = str(left_half_num)

        if length % 2 == 0:
            new_palindrome = new_left_half + new_left_half[::-1]
        else:
            new_palindrome = new_left_half + new_left_half[-2::-1]

        return int(new_palindrome)

    # Find the smallest palindrome greater than n
    # Mirror the left half to form the smallest palindrome
    if length % 2 == 0:
        mirrored = left_half + left_half[::-1]
    else:
        mirrored = left_half + left_half[-2::-1]

    if int(mirrored) > n:
