def amicable_numbers_sum(limit: int) -> int:
    """
    Return the sum of all amicable numbers below the given limit.
    Two numbers a and b are amicable if the sum of proper divisors of a equals b,
    and the sum of proper divisors of b equals a, with a != b.
    """
    def sum_proper_divisors(n: int) -> int:
        if n < 2:
            return 0
        total = 1  # 1 is a proper divisor for all n > 1
        i = 2
        while i * i <= n:
            if n % i == 0:
                total += i
                # Add the corresponding divisor if it's different
                if i != n // i:
                    total += n // i
            i += 1
        return total

    amicable_set = set()
    for a in range(2, limit):
        b = sum_proper_divisors(a)
        if b != a and b < limit and sum_proper_divisors(b) == a:
            amicable_set.add(a)
            amicable_set.add(b)
    return sum(amicable_set)
