import math

def sum_common_divisors(a, b):
    """
    Returns the sum of common divisors of two numbers a and b.
    """
    # Find the Greatest Common Divisor (GCD)
    gcd = math.gcd(a, b)

    # If the GCD is 1, the only common divisor is 1
    if gcd == 1:
        return 1

    # Find all divisors of the GCD
    divisors = []
    for i in range(1, int(math.isqrt(gcd)) + 1):
        if gcd % i == 0:
            divisors.append(i)
            if i != gcd // i:
                divisors.append(gcd // i)

    return sum(divisors)
