def zero_count(arr):
    """
    Calculate the ratio of zeroes to non-zeroes in an array of integers.
    """
    if not arr:
        return 0.0

    zero_count = 0
    for num in arr:
        if num == 0:
            zero_count += 1

    total_non_zero = len(arr) - zero_count
    if total_non_zero == 0:
        return 0.0

