        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return (gcd, x, y)

    g, x0, y0 = extended_gcd(a, b)

    # Scale the solution
    x = x0 * (n // g)
    y = y0 * (n // g)

    return (x, y)
