    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == element:
            first_occurrence = mid
            high = mid - 1  # Continue searching to the left
        elif arr[mid] < element:
            low = mid + 1
        else:
            high = mid - 1

    if first_occurrence == -1:
        return False  # Element not found in the array

    # Use binary search to find the last occurrence of the element
