def get_total_number_of_sequences(m, n):
    if n == 0:
        return 0
    if n == 1:
        return m

    # dp[i] represents the number of valid sequences of length i ending with a specific value
    # We can use a 2D DP array where dp[i][j] is the number of sequences of length i ending with value j
    dp = [[0] * (m + 1) for _ in range(n + 1)]

    # Base case: sequences of length 1
    for j in range(1, m + 1):
        dp[1][j] = 1

    # Fill the DP table
    for i in range(2, n + 1):
        for j in range(1, m + 1):
            # The previous element must be at least half of j and at most j-1
            start = max(1, (j + 1) // 2)
            for k in range(start, j):
                dp[i][j] += dp[i-1][k]

    # Sum up all sequences of length n
    total = sum(dp[n][j] for j in range(1, m + 1))
    return total
