def max_sum_bitonic(arr):
    n = len(arr)
    if n == 0:
        return 0

    # lis[i] will store the length of LIS ending at index i
    lis = [1] * n
    # lds[i] will store the length of LDS starting at index i
    lds = [1] * n

    # Compute LIS values in bottom up manner
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j]:
                lis[i] = max(lis[i], lis[j] + 1)

    # Compute LDS values in bottom up manner
    for i in range(n - 2, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[i] > arr[j]:
