def combinations_colors(lst, n):
    """
    Generate all combinations of length n with repetition from the given list.

    Args:
        lst (list): The list of elements to combine.
        n (int): The length of each combination.

    Returns:
        list: A list of tuples, where each tuple is a combination of elements from lst.
    """
    def generate_combinations(lst, n, prefix=[]):
        if len(prefix) == n:
            yield tuple(prefix)
        else:
            for item in lst:
                yield from generate_combinations(lst, n, prefix + [item])

