import math

def newman_prime(n: int) -> int:
    """
    Returns the nth Newman-Shanks-Williams (NSW) prime number.
    """
    if n < 1:
        raise ValueError("n must be a positive integer")

    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        sqrt_n = int(math.sqrt(num)) + 1
        for i in range(3, sqrt_n, 2):
            if num % i == 0:
                return False
        return True

    def generate_nsw_sequence(k: int) -> list[int]:
        """
        Generates the NSW sequence up to the k-th term.
        NSW sequence is defined by:
        a(0) = 1, a(1) = 1
        a(n) = a(n-1)^2 + a(n-2)^2 for n >= 2
        """
        if k < 0:
            return []
        if k == 0:
            return [1]
        if k == 1:
            return [1, 1]

        a = [1, 1]
        for i in range(2, k + 1):
            next_val = a[-1]**2 + a[-2]**2
            a.append(next_val)
        return a

    count = 0
    k = 0
    while count < n:
        sequence = generate_nsw_sequence(k)
        for num in sequence:
            if is_prime(num):
                count += 1
                if count == n:
                    return num
        k += 1

    # Fallback in case of unexpected behavior
    raise RuntimeError("Failed to find the nth NSW prime")

# Test case
assert newman_prime(3) == 7
