import math

def otherside_rightangle(a, b):
    """
    Calculates the third side of a right-angled triangle.
    If a and b are the legs, it returns the hypotenuse.
    If one is the leg and the other is the hypotenuse, it returns the other leg.
    """
    if a > b:
        a, b = b, a  # Ensure a is the smaller side

    if a**2 + b**2 == b**2:
        # a is a leg, b is the hypotenuse
        return math.sqrt(b**2 - a**2)
    else:
        # Both are legs
        return math.sqrt(a**2 + b**2)
