def max_sum_increasing_subseq(arr, n, k, i):
    if i >= n or k >= n or i >= k:
        return 0

    # dp[i] will store the maximum sum of increasing subsequence ending at index i
    dp = [0] * n

    # Initialize dp with the elements themselves
    for j in range(n):
        dp[j] = arr[j]

    # Compute dp for each index
    for j in range(1, n):
        for p in range(j):
            if arr[j] > arr[p]:
                dp[j] = max(dp[j], dp[p] + arr[j])

    # Find the maximum sum of increasing subsequence ending at index i
    max_sum_ending_at_i = dp[i]

    # Find the maximum sum of increasing subsequence ending at index k
    # that includes arr[k] and is greater than arr[i]
    max_sum_ending_at_k = 0
    for j in range(k):
        if arr[k] > arr[j]:
            max_sum_ending_at_k = max(max_sum_ending_at_k, dp[j])

    # Return the maximum of the two sums
    return max(max_sum_ending_at_i, max_sum_ending_at_k + arr[k])
